INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, created_at, cloudinary_url, public_id) VALUES (266, 'Dibujo para colorear crucero de vacaciones en el mar', 'dibujo-para-colorear-crucero-de-vacaciones-en-el-mar', 'Gran barco crucero navegando por el mar', 'Dibujo para colorear de un gran barco crucero navegando por el mar durante unas vacaciones. Los cruceros transportan turistas que quieren viajar y conocer diferentes lugares.', 'crucero, barco de vacaciones, barco grande, mar, océano, turismo, viaje en barco', 'dibujo-para-colorear-crucero-de-vacaciones-en-el-mar', 5, '2026-03-11T23:00:55.172Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280370/coloring-web/vehiculos/dibujo-para-colorear-crucero-de-vacaciones-en-el-mar.webp', 'coloring-web/vehiculos/dibujo-para-colorear-crucero-de-vacaciones-en-el-mar') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, created_at, cloudinary_url, public_id) VALUES (6, 'Dibujo de ballena saltando en el mar para colorear', 'dibujo-de-ballena-saltando-en-el-mar-para-colorear', 'Ilustración detallada de una ballena jorobada emergiendo de una gran ola en el océano, con nubes de fondo.', 'Un dibujo artístico que captura el movimiento del mar y la magnitud de la ballena. Excelente para enseñar sobre la vida marina mientras se colorea.', 'ballena para colorear, animales marinos, dibujo de océano, ballena jorobada, naturaleza marina, pintar olas del mar.', 'dibujo-de-ballena-saltando-en-el-mar-para-colorear', 1, '2026-02-23T21:41:10.834Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280075/coloring-web/animales/dibujo-de-ballena-saltando-en-el-mar-para-colorear.webp', 'coloring-web/animales/dibujo-de-ballena-saltando-en-el-mar-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, created_at, cloudinary_url, public_id) VALUES (7, 'Dibujo de bisonte bebé tierno para colorear', 'dibujo-de-bisonte-bebe-tierno-para-colorear', 'Ilustración de un pequeño bisonte o búfalo de estilo caricatura frente a una valla de madera, trazos simples.', 'Un diseño adorable de un bisonte cachorro. Su simplicidad lo hace ideal como actividad educativa para niños pequeños en edad preescolar.', 'bisonte para colorear, búfalo bebé, dibujo de granja, animales americanos, colorear para preescolar, dibujo tierno.', 'dibujo-de-bisonte-bebe-tierno-para-colorear', 1, '2026-02-23T21:42:57.964Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280076/coloring-web/animales/dibujo-de-bisonte-bebe-tierno-para-colorear.webp', 'coloring-web/animales/dibujo-de-bisonte-bebe-tierno-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, created_at, cloudinary_url, public_id) VALUES (8, 'Dibujo de bisonte americano en el campo para colorear', 'dibujo-de-bisonte-americano-en-el-campo-para-colorear', 'Dibujo lineal de un bisonte adulto de perfil parado frente a una cerca de madera en una pradera.', 'Una representación clara y fiel del bisonte americano. Ideal para proyectos escolares sobre la fauna de América del Norte o la vida en la llanura.', 'bisonte americano, dibujo de búfalo, animales de la pradera, naturaleza para colorear, dibujo de campo, animales salvajes.', 'dibujo-de-bisonte-americano-en-el-campo-para-colorear', 1, '2026-02-23T21:44:08.193Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280077/coloring-web/animales/dibujo-de-bisonte-americano-en-el-campo-para-colorear.webp', 'coloring-web/animales/dibujo-de-bisonte-americano-en-el-campo-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, created_at, cloudinary_url, public_id) VALUES (10, 'Dibujo de búho realista en una rama para colorear', 'dibujo-de-buho-realista-en-una-rama-para-colorear', 'Ilustración detallada de un búho o lechuza con grandes ojos y plumaje marcado, posado sobre una rama de árbol.', 'Un diseño rico en texturas que permite jugar con diferentes tonalidades de marrones y grises. Perfecto para los amantes de las aves y la observación de la naturaleza.', 'búho para colorear, lechuza para pintar, aves nocturnas, dibujo de búho realista, naturaleza, dibujo para adultos y niños.', 'dibujo-de-buho-realista-en-una-rama-para-colorear', 1, '2026-02-23T21:44:56.557Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280080/coloring-web/animales/dibujo-de-buho-realista-en-una-rama-para-colorear.webp', 'coloring-web/animales/dibujo-de-buho-realista-en-una-rama-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, created_at, cloudinary_url, public_id) VALUES (11, 'Dibujo de perrito cachorro durmiendo en su manta para colorear', 'dibujo-de-perrito-cachorro-durmiendo-en-su-manta-para-colorear', 'Dibujo lineal de un cachorro pequeño descansando plácidamente sobre una alfombra o manta dentro de una casa.', 'Una escena tierna y hogareña que transmite paz. Es un dibujo muy sencillo, ideal para relajarse coloreando a la mascota favorita de la casa.', 'perro para colorear, cachorro durmiendo, mascotas para pintar, dibujo de perrito fácil, colorear animales domésticos.', 'dibujo-de-perrito-cachorro-durmiendo-en-su-manta-para-colorear', 1, '2026-02-23T21:45:19.417Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280081/coloring-web/animales/dibujo-de-perrito-cachorro-durmiendo-en-su-manta-para-colorear.webp', 'coloring-web/animales/dibujo-de-perrito-cachorro-durmiendo-en-su-manta-para-colorear') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
