INSERT INTO images (id, title, slug, alt_text, description, tags, filename, category_id, created_at, cloudinary_url, public_id) VALUES (4, 'Dibujo de águila volando sobre montañas para colorear e imprimir', 'dibujo-de-aguila-volando-sobre-montanas-para-colorear-e-imprimir', 'Ilustración en blanco y negro de un águila calva volando con las alas extendidas sobre montañas y nubes, estilo dibujo para colorear.', 'Esta imagen presenta una ilustración lineal de un águila majestuosa en pleno vuelo, diseñada específicamente para ser utilizada como material educativo o de entretenimiento infantil. El dibujo muestra al ave con las alas desplegadas, sobrevolando un paisaje de picos montañosos y nubes esponjosas. Gracias a sus trazos firmes y espacios definidos, es ideal para que los niños practiquen su motricidad fina coloreando con lápices, ceras o témperas. Es un recurso perfecto para padres y maestros que buscan dibujos de animales de la naturaleza para imprimir.', 'águila para colorear, dibujo de águila, animales para pintar, águila volando, dibujo infantil, ilustración de montañas, imprimir gratis, actividades para niños, dibujo en blanco y negro, aves rapaces para colorear.', 'dibujo-de-aguila-volando-sobre-montanas-para-colorear-e-imprimir', 1, '2026-02-23T15:41:55.246Z', 'https://res.cloudinary.com/dqkf4hjul/image/upload/v1773280197/coloring-web/animales/dibujo-de-aguila-volando-sobre-montanas-para-colorear-e-imprimir.webp', 'coloring-web/animales/dibujo-de-aguila-volando-sobre-montanas-para-colorear-e-imprimir') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, slug = EXCLUDED.slug, alt_text = EXCLUDED.alt_text, description = EXCLUDED.description, tags = EXCLUDED.tags, filename = EXCLUDED.filename, category_id = EXCLUDED.category_id, created_at = EXCLUDED.created_at, cloudinary_url = EXCLUDED.cloudinary_url, public_id = EXCLUDED.public_id;
